def countGoodIntegers(self, n: int, k: int) -> int:
    count = 0
    for i in range(1, n+1):
        for j in range(1, k+1):
            num = i*j
            if num > 9:
                num = str(num)
                num = ''.join(sorted(int(digit) for digit in num)
                if num == num[::-1] and int(num) % k == 0:
                    count += 1
    return count

